require "event.BaseEvent"

ThunderEvent = class("ThunderEvent", BaseEvent)

function ThunderEvent:onTriggered(player)
    --MsgSender.sendTopTipsToTarget(0, 5, Messages:msgThunder(player.name,1))
    MsgSender.sendCenterTipsToTarget(player.rakssid, 5, Messages:msgThunderToOwn())
    local period = tonumber(self.config.param1)
    local times = self.config.time / period
    local index = 0
    local targets = GameMatch:randomPlayers(times, player.rakssid, player:getTeamId())
    for _, target in pairs(targets) do
        MsgSender.sendBottomTipsToTarget(target.rakssid, 5, Messages:msgThunder(GameMatch:nameAndTeamId(player)))
        LuaTimer:schedule(function(targetUserId, damage, height, attacker)
            local pTarget = PlayerManager:getPlayerByUserId(targetUserId)
            if pTarget == nil then
                return
            end
            local pos = pTarget:getPosition()
            EngineWorld:addSimpleEffect("149_thunher.effect", VectorUtil.newVector3(pos.x, pos.y, pos.z),
                    0, 5000, 0, 2)
            pTarget.entityPlayerMP:specialJump(1, 1.0, 1.0)
            if pTarget:onMountHunt(damage) then
                return
            end

            pTarget:updateHurtInfo(ReportUtil.DeadType.Event, self.config.id, 0, attacker)
            pTarget:subHealth(damage)
        end, index * period * 1000, nil, target.userId, (self.config.param2), tonumber(self.config.param3), player.userId)
        index = index + 1
    end
end

return ThunderEvent
